class Solution:
    def makesquare(self, matchsticks: list[int]) -> bool:
        if not matchsticks:
            return False

        total_sum = sum(matchsticks)

        if total_sum % 4 != 0:
            return False

        side_length = total_sum // 4

        for stick in matchsticks:
            if stick > side_length:
                return False

        matchsticks.sort(reverse=True)

        sides = [0] * 4

        def backtrack(current_index):
            if current_index == len(matchsticks):
                return True

            for i in range(4):
                if sides[i] + matchsticks[current_index] <= side_length:
                    sides[i] += matchsticks[current_index]

                    if backtrack(current_index + 1):
                        return True

                    sides[i] -= matchsticks[current_index]

            return False

        return backtrack(0)
